<template>
	<view class="container">
		<div class="box2">
			<Mtitle title="Stock"></Mtitle>
			<view class="box">
				<view class="scrollContent">
					<scroll-view scroll-y="true" class="scrollView">
						<!-- 加载中 -->
						<view v-if="loading" class="loading" style="text-align: center; padding: 20px;">
							<text>加载中...</text>
						</view>

						<!-- 没有数据 -->
						<view v-else-if="inventory.length === 0" class="empty"
							style="text-align: center; color: #999; padding: 20px;">
							<text>暂无库存</text>
						</view>
						<stockBar v-for="product in inventory" :key="product.product_id" :title="product.product_name"
							:color="getStockColor(product.quantity, product.alert_threshold)"
							:content="`数量: ${product.quantity}`"
							:status="getStockStatus(product.quantity, product.alert_threshold)" class="as" />
					</scroll-view>
				</view>
			</view>

			<!-- 导航按钮 -->

			<navigator url="/pages/orderDetails/orderDetails"></navigator>

			<!-- 底部按钮组 -->
			<view class="buttonLump">
				<newBar title="new" to="/pages/orders/orders"></newBar>
				<newBar title="post" to="/pages/orderDetails/orderDetails"></newBar>
			</view>
		</div>
	</view>
</template>

<script setup>
	import {
		onMounted,
		ref
	} from 'vue'

	//  定义响应式数据
	const inventory = ref([]) // 订单列表
	const loading = ref(true) // 加载状态

	const getStockStatus = (quantity, threshold) => {
		if (quantity === 0) return '缺货'
		if (!threshold) return '无阈值'
		if (quantity <= threshold) return '库存预警'
		if (quantity <= threshold * 2) return '库存偏低'
		return '库存正常'
	}
	const getStockColor = (quantity, threshold) => {
		if (!threshold) return 'blue'
		if (quantity === 0) return 'gray' // 无库存
		if (quantity <= threshold) return 'red' // 低于预警
		if (quantity <= threshold * 2) return 'orange' // 接近预警
		return 'green' // 安全库存
	}

	//  获取我的订单数据
	const getMyInventory = async () => {
		loading.value = true
		try {
			// 获取 token
			const token = uni.getStorageSync('token')
			if (!token) {
				uni.showToast({
					title: '请先登录',
					icon: 'none'
				})
				return
			}

			const res = await uni.request({
				url: 'http://localhost:5000/api/inventory/inventory',
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			// 处理响应
			if (res.statusCode === 200) {
				inventory.value = res.data.data // 赋值订单列表
				console.log('获取到的库存:', res.data.data)
			} else {
				uni.showToast({
					title: res.data.message || '获取库存失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('获取失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}

	//  页面加载时获取数据
	onMounted(() => {
		getMyInventory()
	})
</script>

<style scoped>
	.buttonLump {
		margin-top: 50px;
	}

	.scrollView {
		height: 830rpx;
	}

	.scrollContent {
		display: flex;
		justify-content: center;
		margin-top: 20rpx;
	}

	.container {
		background-image: url('@/static/images/background/屏幕截图 2025-08-11 135835.png');
		background-size: cover;
		background-position: center center;
		background-repeat: no-repeat;
		background-attachment: fixed;
		width: 100%;
		height: 100vh;
	}

	.as {
		margin-top: 5px;
	}
</style>